import React, { useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const Footer = () => {
    const { t } = useTranslation();

    useEffect(() => {
        // Create floating bubbles
        const createBubbles = () => {
            const bubblesContainer = document.querySelector('.floating-bubbles');
            if (!bubblesContainer) return;

            for (let i = 0; i < 10; i++) {
                const bubble = document.createElement('div');
                bubble.className = 'bubble absolute bg-white/10 rounded-full';

                const size = Math.random() * 60 + 20;
                const left = Math.random() * 100;
                const delay = Math.random() * 8;

                bubble.style.width = `${size}px`;
                bubble.style.height = `${size}px`;
                bubble.style.left = `${left}%`;
                bubble.style.bottom = '0';
                bubble.style.animationDelay = `${delay}s`;
                bubble.style.animation = 'float 8s ease-in-out infinite';

                bubblesContainer.appendChild(bubble);
            }
        };

        createBubbles();

        return () => {
            const bubblesContainer = document.querySelector('.floating-bubbles');
            if (bubblesContainer) {
                bubblesContainer.innerHTML = '';
            }
        };
    }, []);

    return (
        <>
            <style jsx>{`
                .footer-wave {
                    position: absolute;
                    top: 0;
                    left: 0;
                    width: 100%;
                    height: 100px;
                    overflow: hidden;
                }

                .wave {
                    position: absolute;
                    bottom: 0;
                    left: 0;
                    width: 200%;
                    height: 100px;
                    background: url('data:image/svg+xml;utf8,<svg viewBox="0 0 1200 120" xmlns="http://www.w3.org/2000/svg"><path d="M321.39 56.44c58-10.79 114.16-30.13 172-41.86 82.39-16.72 168.19-17.73 250.45-.39C823.78 31 906.67 72 985.66 92.83c70.05 18.48 146.53 26.09 214.34 3V0H0v27.35a600.21 600.21 0 00321.39 29.09z" fill="rgba(255,255,255,0.2)"/></svg>');
                    background-size: 1200px 100px;
                    opacity: 0.5;
                }

                .wave-1 {
                    animation: animate 30s linear infinite;
                    z-index: 1000;
                    opacity: 0.5;
                    animation-delay: 0s;
                    bottom: 0;
                }

                .wave-2 {
                    animation: animate2 15s linear infinite;
                    z-index: 999;
                    opacity: 0.3;
                    animation-delay: -5s;
                    bottom: 10px;
                }

                .wave-3 {
                    animation: animate 30s linear infinite;
                    z-index: 998;
                    opacity: 0.2;
                    animation-delay: -2s;
                    bottom: 15px;
                }

                @keyframes animate {
                    0% { transform: translateX(0) translateZ(0); }
                    100% { transform: translateX(-50%) translateZ(0); }
                }

                @keyframes animate2 {
                    0% { transform: translateX(0) translateZ(0) scaleY(1.2); }
                    100% { transform: translateX(-50%) translateZ(0) scaleY(1.2); }
                }

                .footer-heading-line {
                    position: relative;
                }

                .footer-heading-line::after {
                    content: '';
                    position: absolute;
                    left: 0;
                    bottom: -8px;
                    height: 3px;
                    width: 50px;
                    background-color: #fff;
                    transform: scaleX(0);
                    transform-origin: left;
                    animation: grow 0.5s forwards;
                    animation-delay: 0.3s;
                }

                @keyframes grow {
                    to { transform: scaleX(1); }
                }

                .footer-link-arrow {
                    position: relative;
                    padding-left: 15px;
                    transition: all 0.3s ease;
                }

                .footer-link-arrow::before {
                    content: '→';
                    position: absolute;
                    left: 0;
                    opacity: 0;
                    transition: all 0.3s ease;
                }

                .footer-link-arrow:hover {
                    padding-left: 25px;
                }

                .footer-link-arrow:hover::before {
                    opacity: 1;
                }

                .social-icon-animated {
                    animation: fadeIn 0.5s forwards;
                    opacity: 0;
                }

                .social-icon-animated:nth-child(1) { animation-delay: 0.1s; }
                .social-icon-animated:nth-child(2) { animation-delay: 0.2s; }
                .social-icon-animated:nth-child(3) { animation-delay: 0.3s; }
                .social-icon-animated:nth-child(4) { animation-delay: 0.4s; }
                .social-icon-animated:nth-child(5) { animation-delay: 0.5s; }

                @keyframes fadeIn {
                    to { opacity: 1; }
                }

                @keyframes float {
                    0%, 100% { transform: translateY(0) rotate(0deg); }
                    50% { transform: translateY(-20px) rotate(180deg); }
                }

                .bubble {
                    animation: float 8s ease-in-out infinite;
                }
            `}</style>

            <footer className="relative pt-16 pb-8 px-5 overflow-hidden text-white bg-gradient-to-br from-blue-900 via-red-600 to-yellow-500 dark:from-gray-900 dark:via-gray-800 dark:to-gray-700 transition-all duration-300">
                {/* Animated Waves */}
                <div className="footer-wave">
                    <div className="wave wave-1"></div>
                    <div className="wave wave-2"></div>
                    <div className="wave wave-3"></div>
                </div>

                {/* Floating Bubbles */}
                <div className="floating-bubbles absolute top-0 left-0 w-full h-full overflow-hidden z-0"></div>

                {/* Main Footer Content */}
                <div className="flex justify-between flex-wrap max-w-6xl mx-auto relative z-10">
                    {/* Company Info Section */}
                    <div className="flex-1 p-5 min-w-[250px]">
                        <h3 className="footer-heading-line mb-5 text-2xl font-semibold text-white dark:text-gray-100 transition-colors duration-300">
                            FIA Portal
                        </h3>
                        <p className="mb-5 text-white/90 dark:text-gray-300 leading-relaxed transition-colors duration-300">
                            {t('footer.description')}
                        </p>
                        <div className="flex gap-5 mt-5">
                            <a href="https://facebook.com" target="_blank" rel="noopener noreferrer" 
                               className="social-icon-animated w-10 h-10 flex items-center justify-center rounded-full bg-white/20 dark:bg-gray-700/50 text-white dark:text-gray-300 text-xl cursor-pointer transition-all duration-300 relative overflow-hidden no-underline hover:-translate-y-1 hover:bg-white hover:text-blue-900 dark:hover:bg-gray-600 dark:hover:text-white">
                                <i className="fab fa-facebook-f"></i>
                            </a>
                            <a href="https://twitter.com" target="_blank" rel="noopener noreferrer"
                               className="social-icon-animated w-10 h-10 flex items-center justify-center rounded-full bg-white/20 dark:bg-gray-700/50 text-white dark:text-gray-300 text-xl cursor-pointer transition-all duration-300 relative overflow-hidden no-underline hover:-translate-y-1 hover:bg-white hover:text-blue-900 dark:hover:bg-gray-600 dark:hover:text-white">
                                <i className="fab fa-twitter"></i>
                            </a>
                            <a href="https://instagram.com" target="_blank" rel="noopener noreferrer"
                               className="social-icon-animated w-10 h-10 flex items-center justify-center rounded-full bg-white/20 dark:bg-gray-700/50 text-white dark:text-gray-300 text-xl cursor-pointer transition-all duration-300 relative overflow-hidden no-underline hover:-translate-y-1 hover:bg-white hover:text-blue-900 dark:hover:bg-gray-600 dark:hover:text-white">
                                <i className="fab fa-instagram"></i>
                            </a>
                            <a href="https://linkedin.com" target="_blank" rel="noopener noreferrer"
                               className="social-icon-animated w-10 h-10 flex items-center justify-center rounded-full bg-white/20 dark:bg-gray-700/50 text-white dark:text-gray-300 text-xl cursor-pointer transition-all duration-300 relative overflow-hidden no-underline hover:-translate-y-1 hover:bg-white hover:text-blue-900 dark:hover:bg-gray-600 dark:hover:text-white">
                                <i className="fab fa-linkedin-in"></i>
                            </a>
                            <a href="https://youtube.com" target="_blank" rel="noopener noreferrer"
                               className="social-icon-animated w-10 h-10 flex items-center justify-center rounded-full bg-white/20 dark:bg-gray-700/50 text-white dark:text-gray-300 text-xl cursor-pointer transition-all duration-300 relative overflow-hidden no-underline hover:-translate-y-1 hover:bg-white hover:text-blue-900 dark:hover:bg-gray-600 dark:hover:text-white">
                                <i className="fab fa-youtube"></i>
                            </a>
                        </div>
                    </div>

                    {/* Quick Links */}
                    <div className="flex-1 p-5 min-w-[250px]">
                        <h3 className="footer-heading-line mb-5 text-xl font-semibold text-white dark:text-gray-100 transition-colors duration-300">
                            {t('footer.quickLinks.title')}
                        </h3>
                        <ul className="list-none">
                            <li className="mb-4">
                                <Link to="/" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.quickLinks.home')}
                                </Link>
                            </li>
                            <li className="mb-4">
                                <Link to="/about" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.quickLinks.about')}
                                </Link>
                            </li>
                            <li className="mb-4">
                                <Link to="/courses" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.quickLinks.courses')}
                                </Link>
                            </li>
                            <li className="mb-4">
                                <Link to="/apply" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.quickLinks.apply')}
                                </Link>
                            </li>
                            <li className="mb-4">
                                <Link to="/contact" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.quickLinks.contact')}
                                </Link>
                            </li>
                        </ul>
                    </div>

                    {/* Programs */}
                    <div className="flex-1 p-5 min-w-[250px]">
                        <h3 className="footer-heading-line mb-5 text-xl font-semibold text-white dark:text-gray-100 transition-colors duration-300">
                            {t('footer.programs.title')}
                        </h3>
                        <ul className="list-none">
                            <li className="mb-4">
                                <Link to="/courses/web-development" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.programs.webDevelopment')}
                                </Link>
                            </li>
                            <li className="mb-4">
                                <Link to="/courses/data-science" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.programs.dataScience')}
                                </Link>
                            </li>
                            <li className="mb-4">
                                <Link to="/courses/cybersecurity" className="footer-link-arrow text-white dark:text-gray-300 no-underline text-base transition-all duration-300 hover:text-white/90 dark:hover:text-gray-200">
                                    {t('footer.programs.cybersecurity')}
                                </Link>
